“命令式风格”：
void minmax1(long a[], long b[], long n)&#123;
	long i;
    for(i &#x3D; 0; i &lt; n; i++)&#123;
        if(a[i] &gt; b[i])&#123;
            long temp &#x3D; a[i];
            a[i] &#x3D; b[i];
            b[i] &#x3D; temp;
        &#125;
    &#125;
&#125;

“功能式风格”：
void minmax2(long a[], long b[], long n)&#123;
    long i;
    for(i &#x3D; 0; i &lt; n; i++)&#123;
        long min &#x3D; a[i] &lt; b[i] ? a[i] : b[i];
        long max &#x3D; a[i] &lt; b[i] ? b[i] : a[i];
        a[i] &#x3D; min;
        b[i] &#x3D; max;
    &#125;
&#125;

不是所有的条件行为都能够使用条件数据传送来实现，而处理器往往对于这种不可预测情况的处理非常糟糕。比如上例，在数据任意的情况下，第一种“命令式”CPE的变化相差大，相反，“功能式”在这两种情况下是一致的。
