我们写出递归函数：
int fun7(Node *root, int val)&#123;
    if(root &#x3D;&#x3D; NULL)
        return -1;
    if(root-&gt;value &#x3D;&#x3D; val)
         return 0;       
    else if(root-&gt;value &gt; val)
    	return 2*fun7(root-&gt;left,val);
    else if(root-&gt;value &lt; val)
        return 2*fun7(root-&gt;right,val)+1;
&#125;

